import React, { Fragment, useState } from "react";
import {
  BrowserRouter as Router,
  Route,
  Routes,
  Navigate,
} from "react-router-dom";

//routes/components
import Home from "./routes/Home";
import Login from "./routes/Login";
import Registration from "./routes/Registration";

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const setAuth = (boolean) => {
    setIsAuthenticated(boolean);
  };
  return (
    <Fragment>
      <Router>
        <Routes>
          <Route
            path="/"
            Component={Home}
            render={(props) =>
              !isAuthenticated ? (
              <Home {...props} />
               ):( 
               <Navigate to="/login" />
               )
            }
          />
          <Route
            path="/login"
            Component={Login}
            render={(props) =>
              !isAuthenticated ? (
              <Login {...props} /> 
              ): (
              <Navigate to="/login" />
              )
            }
          />
          <Route
            path="/registration"
            Component={Registration}
            render={(props) =>
              !isAuthenticated ? (
                <Registration {...props} />
              ) : (
                <Navigate to="/login" />
              )
            }
          />
        </Routes>
      </Router>
      {/* Hello  */}
    </Fragment>
  );
};
export default App;
